  1	import * as React from 'react';
  2	import { useSafeK8sGet } from '@odf/core/hooks';
  3	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  4	import { CephBlockPoolModel } from '@odf/shared';
  5	import { ONE_SECOND } from '@odf/shared/constants';
  6	import { StatusBox } from '@odf/shared/generic';
  7	import { ModalTitle, ModalFooter } from '@odf/shared/generic/ModalTitle';
  8	import {
  9	  HandlePromiseProps,
 10	  withHandlePromise,
 11	} from '@odf/shared/generic/promise-component';
 12	import { ModalBody } from '@odf/shared/modals/Modal';
 13	import { StorageClusterModel } from '@odf/shared/models';
 14	import { getNamespace } from '@odf/shared/selectors';
 15	import { CephClusterKind, StorageClusterKind } from '@odf/shared/types';
 16	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 17	import {
 18	  getValidWatchK8sResourceObj,
 19	  referenceForModel,
 20	} from '@odf/shared/utils';
 21	import {
 22	  K8sResourceCommon,
 23	  K8sResourceKind,
 24	  k8sCreate,
 25	  useK8sWatchResource,
 26	} from '@openshift-console/dynamic-plugin-sdk';
 27	import { ModalComponent } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 28	import { Modal, ModalVariant } from '@patternfly/react-core';
 29	import { PoolState, PoolProgress, PoolType } from '../../constants';
 30	import { StoragePoolStatus, StoragePoolBody } from '../../storage-pool/body';
 31	import {
 32	  StoragePoolDefinitionText,
 33	  createFsPoolRequest,
 34	  getPoolKindObj,
 35	  poolResource,
 36	} from '../../storage-pool/CreateStoragePool';
 37	import {
 38	  StoragePoolActionType,
 39	  blockPoolInitialState,
 40	  storagePoolReducer,
 41	} from '../../storage-pool/reducer';
 42	import { StoragePoolKind } from '../../types';
 43	import { StoragePoolModalFooter, FooterPrimaryActions } from './modal-footer';
 44	import './storage-pool-modal.scss';
 45	
 46	export const CreateStoragePoolModal = withHandlePromise(
 47	  (props: CreateStoragePoolModalProps) => {
 48	    const {
 49	      cephCluster,
 50	      onPoolCreation,
 51	      handlePromise,
 52	      errorMessage,
 53	      defaultDeviceClass,
 54	      poolType,
 55	      existingNames,
 56	      filesystemName,
 57	    } = props;
 58	    const { t } = useCustomTranslation();
 59	    const { systemFlags, areFlagsLoaded, flagsLoadError } =
 60	      useODFSystemFlagsSelector();
 61	    const poolNs = getNamespace(cephCluster);
 62	    const clusterName = systemFlags[poolNs]?.ocsClusterName;
 63	    const [storageCluster, storageClusterLoaded, storageClusterLoadError] =
 64	      useSafeK8sGet<StorageClusterKind>(
 65	        StorageClusterModel,
 66	        clusterName,
 67	        poolNs
 68	      );
 69	
 70	    const [state, dispatch] = React.useReducer(
 71	      storagePoolReducer,
 72	      blockPoolInitialState
 73	    );
 74	    const [isSubmit, setIsSubmit] = React.useState(false);
 75	    const [timer, setTimer] = React.useState<NodeJS.Timer>(null);
 76	
 77	    const poolName = state.poolName;
 78	
 79	    const MODAL_TITLE = t('Create Storage Pool');
 80	
 81	    // Watch newly created pool (or CR owner for cephfs) after submit
 82	    const initResource =
 83	      poolType === PoolType.FILESYSTEM
 84	        ? {
 85	            kind: referenceForModel(StorageClusterModel),
 86	            namespaced: true,
 87	            isList: false,
 88	            name: clusterName,
 89	            namespace: poolNs,
 90	          }
 91	        : poolResource(poolName, poolNs);
 92	
 93	    const [resource, resourceLoaded, resourceLoadError] =
 94	      useK8sWatchResource<K8sResourceKind>(
 95	        getValidWatchK8sResourceObj(initResource, isSubmit && !!poolName)
 96	      );
 97	
 98	    const runPostCreationActions = React.useCallback(() => {
 99	      if (
100	        resource &&
101	        resourceLoaded &&
102	        resource?.status?.phase === PoolState.READY
103	      ) {
104	        dispatch({
105	          type: StoragePoolActionType.SET_POOL_STATUS,
106	          payload: PoolProgress.CREATED,
107	        });
108	        setIsSubmit(false);
109	        clearTimeout(timer);
110	        onPoolCreation(
111	          poolType === PoolType.FILESYSTEM
112	            ? `${filesystemName}-${poolName}`
113	            : poolName
114	        );
115	      } else if (
116	        resourceLoaded &&
117	        (resource?.status?.phase === PoolState.RECONCILE_FAILED ||
118	          resource?.status?.phase === PoolState.FAILURE)
119	      ) {
120	        dispatch({
121	          type: StoragePoolActionType.SET_POOL_STATUS,
122	          payload: PoolProgress.NOTREADY,
123	        });
124	        setIsSubmit(false);
125	        clearTimeout(timer);
126	      } else if (
127	        resourceLoaded &&
128	        resourceLoadError &&
129	        resourceLoadError?.response?.status !== 404
130	      ) {
131	        dispatch({
132	          type: StoragePoolActionType.SET_POOL_STATUS,
133	          payload: PoolProgress.FAILED,
134	        });
135	        setIsSubmit(false);
136	        clearTimeout(timer);
137	      }
138	    }, [
139	      filesystemName,
140	      onPoolCreation,
141	      poolName,
142	      poolType,
143	      resource,
144	      resourceLoadError,
145	      resourceLoaded,
146	      timer,
147	    ]);
148	
149	    React.useEffect(() => {
150	      if (isSubmit) {
151	        runPostCreationActions();
152	      }
153	    }, [isSubmit, runPostCreationActions]);
154	
155	    // Create new pool
156	    const createPool = () => {
157	      if (state.poolStatus === '') {
158	        dispatch({
159	          type: StoragePoolActionType.SET_POOL_STATUS,
160	          payload: PoolProgress.PROGRESS,
161	        });
162	        let createRequest: () => Promise<K8sResourceCommon>;
163	        if (poolType === PoolType.FILESYSTEM) {
164	          createRequest = createFsPoolRequest(state, storageCluster);
165	        } else {
166	          const poolObj: StoragePoolKind = getPoolKindObj(
167	            state,
168	            poolNs,
169	            defaultDeviceClass
170	          );
171	          createRequest = () =>
172	            k8sCreate({ model: CephBlockPoolModel, data: poolObj });
173	        }
174	
175	        handlePromise(
176	          createRequest(),
177	          () => {
178	            setIsSubmit(true);
179	            // The modal will wait in order to get feedback from Rook
180	            const timeoutTimer = setTimeout(() => {
181	              dispatch({
182	                type: StoragePoolActionType.SET_POOL_STATUS,
183	                payload: PoolProgress.TIMEOUT,
184	              });
185	              setIsSubmit(false);
186	            }, 30 * ONE_SECOND);
187	            setTimer(timeoutTimer);
188	          },
189	          () => {
190	            dispatch({
191	              type: StoragePoolActionType.SET_POOL_STATUS,
192	              payload: PoolProgress.FAILED,
193	            });
194	          }
195	        );
196	      }
197	    };
198	
199	    const isLoaded = storageClusterLoaded && areFlagsLoaded;
200	    const isLoadError = storageClusterLoadError || flagsLoadError;
201	
202	    if (isLoaded && !isLoadError) {
203	      return (
204	        <Modal
205	          isOpen
206	          onClose={props.closeModal}
207	          className="modal-content storage-pool__modal"
208	          variant={ModalVariant.medium}
209	          header={
210	            <>
211	              <ModalTitle>{MODAL_TITLE}</ModalTitle>
212	              <StoragePoolDefinitionText className="pf-v6-u-ml-xl" />
213	            </>
214	          }
215	        >
216	          <ModalBody>
217	            {state.poolStatus ? (
218	              <div key="progress-modal">
219	                <StoragePoolStatus
220	                  status={state.poolStatus}
221	                  name={poolName}
222	                  error={errorMessage}
223	                />
224	              </div>
225	            ) : (
226	              <StoragePoolBody
227	                cephCluster={cephCluster}
228	                state={state}
229	                dispatch={dispatch}
230	                showPoolStatus
231	                poolType={poolType}
232	                existingNames={existingNames}
233	                disablePoolType
234	                prefixName={filesystemName}
235	              />
236	            )}
237	          </ModalBody>
238	          <ModalFooter inProgress={state.poolStatus === PoolProgress.PROGRESS}>
239	            <StoragePoolModalFooter
240	              state={state}
241	              dispatch={dispatch}
242	              onSubmit={createPool}
243	              cancel={props.closeModal}
244	              close={props.closeModal}
245	              primaryAction={FooterPrimaryActions(t).CREATE}
246	            />
247	          </ModalFooter>
248	        </Modal>
249	      );
250	    }
251	    return <StatusBox loaded={isLoaded} loadError={isLoadError} />;
252	  }
253	);
254	
255	export type CreateStoragePoolModalProps = {
256	  cephCluster?: CephClusterKind;
257	  onPoolCreation: (name: string) => void;
258	  defaultDeviceClass: string;
259	  poolType: PoolType;
260	  existingNames: string[];
261	  filesystemName?: string;
262	} & React.ComponentProps<ModalComponent> &
263	  HandlePromiseProps;

